    b"}} {{ message.content }}\x0d\x0a        {% endfor %}\x0d\x0a        {% endfor %}\x0d\x0a\x0d\x0a        "
    b"Session memories for this session:\x0d\x0a        {% for memory in session_memories %}"
    b"\x0d\x0a        - {{ memory.title }}\x0d\x0a          Tags: {{ memory.tags }}\x0d\x0a          cre"
